def flipBitsToTarget(num, target):
    count = bin(num).count('1')
    if count == target:
        return num
    while count != target:
        if count > target:
            num -= 1
            count -= bin(num).count('1')
        else:
            num += 1
            count += bin(num).count('1')
    return num

class Solution:
    def flipBitsToTarget(self, num: int, target: int) -> int:
        return flipBitsToTarget(num, target)

def test():
    s = Solution()
    print(s.flipBitsToTarget(7, 3))
    print(s.flipBitsToTarget(10, 3))
def main():
    test()
