using namespace std;

class Solution {
public:
int flipBitsToTarget(int num, int target) {
    int count = bin(num)[2].count('1');
    if (count == target) {
        return num;
    }
    while (count != target) {
        if (count > target) {
            num--;
            count -= bin(num)[2].count('1');
        } else {
            num++;
            count += bin(num)[2].count('1');
        }
    }
    return num;
}
